// ============================================================================
// LOAD BRAND MEMORY - Creative MCP V5 (Cloud Native)
// ============================================================================

return [{
  json: {
    brand_id: "ak_v4_demo",
    brand_name: "The Hive",

    visual_identity: {
      style: "Minimalist, Tech, Neon Accents",
      mood: "Bold, Futuristic, Premium",
      hex_colors: {
        primary: "#000000",
        secondary: "#FFFFFF",
        accent_1: "#FF00FF",
        accent_2: "#00FFFF",
        accent_3: "#FFD700",
        danger: "#EF4444",
        success: "#10B981"
      },
      fonts: {
        headings: "Inter",
        body: "Inter",
        display: "Space Grotesk"
      },
      design_rules: [
        "Fond sombre obligatoire (noir ou gradient)",
        "Texte blanc ou neon sur fond sombre",
        "Accent magenta pour les CTA",
        "Max 3 elements visuels par image",
        "Espace negatif min 30%"
      ]
    },

    tone_of_voice: {
      personality: "Bold, Direct, Urgent",
      formality: "vous",
      writing_style: {
        sentence_length: "court",
        power_words: true,
        questions: true,
        numbers: true
      },
      power_words: ["Instant", "Garanti", "Exclusif", "Limite", "Maintenant", "Gratuit", "Prouve", "Secret", "Nouveau", "Decouvrez", "Enfin", "Stop"],
      banned_words: ["pas cher", "discount", "promo", "soldes", "meilleur", "numero 1", "leader", "revolutionnaire", "magique", "miracle", "garanti 100%", "sans risque"],
      hook_templates: {
        pain_point: "Stop aux [pain_point]. Voici la solution.",
        stat: "[Stat]% des [cible] font cette erreur.",
        question: "Vous perdez [X] par mois a cause de [probleme]?",
        curiosity: "Ce que personne ne vous dit sur [sujet]."
      }
    },

    platform_specs: {
      meta_feed: { aspect_ratio: "1:1", dimensions: "1080x1080", text_safe_zone: "center", max_text_ratio: 0.20 },
      meta_story: { aspect_ratio: "9:16", dimensions: "1080x1920", text_safe_zone: "center_middle", max_text_ratio: 0.20 },
      meta_reel: { aspect_ratio: "9:16", dimensions: "1080x1920", text_safe_zone: "center", max_text_ratio: 0.15 },
      linkedin_feed: { aspect_ratio: "1.91:1", dimensions: "1200x628", text_safe_zone: "right", max_text_ratio: 0.25 },
      google_display: { aspect_ratio: "1.91:1", dimensions: "1200x628", text_safe_zone: "center", max_text_ratio: 0.20 },
      youtube_thumbnail: { aspect_ratio: "16:9", dimensions: "1280x720", text_safe_zone: "left_center", max_text_ratio: 0.30 }
    },

    products: [
      { id: "hive_pro", name: "The Hive Pro", price: "99EUR/mois", tagline: "4 agents IA pour le prix d'un outil" },
      { id: "hive_enterprise", name: "The Hive Enterprise", price: "Sur devis", tagline: "Solution sur-mesure pour grandes equipes" }
    ],

    creative_learnings: [
      { insight: "Visages humains +35% CTR", confidence: 0.85 },
      { insight: "Chiffres dans titre +28% engagement", confidence: 0.82 },
      { insight: "Questions directes +22% click", confidence: 0.78 },
      { insight: "Fond sombre +18% attention", confidence: 0.75 }
    ]
  }
}];

// ============================================================================
// PREPARE CREATIVE CONTEXT - Detect mode (brainstorm vs production)
// ============================================================================

const brandMemory = $('Load Brand Memory').item.json;
const userInput = $('Webhook Trigger').item.json;

const message = (userInput.body?.message || userInput.message || "").toLowerCase();

// ─────────────────────────────────────────────────────────────────────────
// DETECT MODE: Brainstorming vs Production vs Need Clarification
// ─────────────────────────────────────────────────────────────────────────
let detectedMode = 'unknown';
let needsClarification = false;

// Keywords for brainstorming
const brainstormKeywords = ['idee', 'idées', 'concept', 'brainstorm', 'propose', 'suggere', 'inspiration', 'angle', 'hook', 'accroche'];
// Keywords for production
const productionKeywords = ['cree', 'crée', 'genere', 'génère', 'fais', 'produis', 'ecris', 'écris', 'redige', 'rédige', 'pub', 'publicite', 'publicité', 'ad', 'visuel', 'image'];

if (brainstormKeywords.some(kw => message.includes(kw))) {
  detectedMode = 'brainstorming';
} else if (productionKeywords.some(kw => message.includes(kw))) {
  detectedMode = 'production';
} else if (message.length < 20) {
  // Message trop court = besoin de clarification
  needsClarification = true;
  detectedMode = 'needs_clarification';
} else {
  // Default: essayer de produire
  detectedMode = 'production';
}

// ─────────────────────────────────────────────────────────────────────────
// DETECT PLATFORM
// ─────────────────────────────────────────────────────────────────────────
let platform = 'meta_feed';
if (message.includes('story') || message.includes('stories')) platform = 'meta_story';
else if (message.includes('reel')) platform = 'meta_reel';
else if (message.includes('linkedin')) platform = 'linkedin_feed';
else if (message.includes('google') || message.includes('display')) platform = 'google_display';
else if (message.includes('youtube') || message.includes('thumbnail')) platform = 'youtube_thumbnail';

// ─────────────────────────────────────────────────────────────────────────
// DETECT PRODUCT (if mentioned)
// ─────────────────────────────────────────────────────────────────────────
let targetProduct = null;
if (message.includes('pro') || message.includes('99')) {
  targetProduct = brandMemory.products.find(p => p.id === 'hive_pro');
} else if (message.includes('enterprise') || message.includes('entreprise')) {
  targetProduct = brandMemory.products.find(p => p.id === 'hive_enterprise');
}

return [{
  json: {
    user_request: {
      message: userInput.body?.message || userInput.message || "Fais une pub",
      session_id: userInput.body?.session_id || `session_${Date.now()}`,
      timestamp: new Date().toISOString()
    },
    detected_mode: detectedMode,
    needs_clarification: needsClarification,
    creative_params: {
      platform: platform,
      platform_specs: brandMemory.platform_specs[platform],
      target_product: targetProduct
    },
    brand: brandMemory,
    available_products: brandMemory.products
  }
}];

