// ============================================================================
// FORMAT UI RESPONSE - Creative MCP V5
// ============================================================================

const aiOutput = $input.first().json;
let creativeData;

// ─────────────────────────────────────────────────────────────────────────
// PARSE AI OUTPUT
// ─────────────────────────────────────────────────────────────────────────
try {
  if (typeof aiOutput.output === 'string') {
    let cleanOutput = aiOutput.output
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();
    creativeData = JSON.parse(cleanOutput);
  } else if (aiOutput.output && typeof aiOutput.output === 'object') {
    creativeData = aiOutput.output;
  } else if (aiOutput.creative_result) {
    creativeData = aiOutput;
  } else {
    throw new Error('Format de sortie non reconnu');
  }
} catch (e) {
  creativeData = {
    creative_result: {
      mode: 'needs_clarification',
      final_ad: null,
      recommendations: [],
      creative_score: null
    },
    chat_message: {
      content: aiOutput.output || 'Erreur de generation creative.',
      follow_up_questions: ['Pouvez-vous reformuler?']
    },
    context: { mode: 'error', platform: 'meta_feed' }
  };
}

const result = creativeData.creative_result || {};
const chatMsg = creativeData.chat_message || {};
const ctx = creativeData.context || {};

// ─────────────────────────────────────────────────────────────────────────
// BUILD UI COMPONENTS
// ─────────────────────────────────────────────────────────────────────────

const uiComponents = [];

// MODE PRODUCTION: Show Ad Preview
if (result.mode === 'production' && result.final_ad) {
  const ad = result.final_ad;

  uiComponents.push({
    type: 'AD_PREVIEW',
    data: {
      platform: ad.platform || 'meta_feed',
      format: ad.platform?.includes('story') ? 'story' : 'feed',
      image_url: 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=1080&h=1080&fit=crop',
      headline: ad.headline,
      primary_text: ad.body_text,
      description: ad.subheadline,
      cta: (ad.cta || 'en_savoir_plus').toLowerCase().replace(/ /g, '_'),
      destination_url: 'https://thehive.ai',
      embedded_text: ad.embedded_text,
      visual_description: ad.visual_description,
      creative_rationale: ad.rationale,
      trigger_used: ad.creative_angle?.toLowerCase(),
      creative_score: result.creative_score?.brand_consistency || 0.9,
      brand_safety_passed: true
    },
    layout: { width: 'half', order: 1 }
  });

  // Creative Score Card
  if (result.creative_score) {
    uiComponents.push({
      type: 'BRAND_VOICE_CHECK',
      data: {
        overall_score: (result.creative_score.brand_consistency + result.creative_score.emotional_impact + result.creative_score.platform_fit) / 3,
        checks: [
          { name: 'Coherence Marque', status: result.creative_score.brand_consistency > 0.8 ? 'pass' : 'warning', details: `${Math.round(result.creative_score.brand_consistency * 100)}%` },
          { name: 'Impact Emotionnel', status: result.creative_score.emotional_impact > 0.7 ? 'pass' : 'warning', details: `${Math.round(result.creative_score.emotional_impact * 100)}%` },
          { name: 'Fit Plateforme', status: result.creative_score.platform_fit > 0.8 ? 'pass' : 'warning', details: `${Math.round(result.creative_score.platform_fit * 100)}%` },
          { name: 'CTR Estime', status: result.creative_score.estimated_ctr > 2 ? 'pass' : 'neutral', details: `${result.creative_score.estimated_ctr}%` }
        ]
      },
      layout: { width: 'half', order: 2 }
    });
  }
}

// MODE BRAINSTORMING: Show Concept Cards
if (result.mode === 'brainstorming' && result.recommendations?.length > 0) {
  const concepts = result.recommendations.map((rec, idx) => ({
    id: rec.id || `concept_${idx}`,
    name: rec.angle || 'Concept',
    badge: idx === 0 ? 'recommended' : 'alternative',
    preview: {
      headline: rec.hook,
      primary_text: rec.why_it_works,
      visual_idea: rec.visual_idea
    },
    emotion: rec.emotion,
    rationale: rec.why_it_works
  }));

  uiComponents.push({
    type: 'BATTLE_CARD',
    data: {
      title: 'Concepts Creatifs',
      test_hypothesis: 'Choisissez un angle a developper',
      variants: concepts,
      selection_prompt: 'Quel concept souhaitez-vous developper?',
      agent_recommendation: {
        recommended_variant_id: concepts[0]?.id,
        reason: concepts[0]?.rationale,
        confidence: 0.85
      }
    },
    layout: { width: 'full', order: 1 }
  });
}

// MODE CLARIFICATION: Show Options
if (result.mode === 'needs_clarification') {
  const options = creativeData.clarification_options || ['Option 1', 'Option 2'];

  uiComponents.push({
    type: 'ACTION_BUTTONS',
    data: {
      layout: 'vertical',
      actions: options.map((opt, idx) => ({
        id: `option_${idx}`,
        label: opt,
        icon: 'arrow_right',
        action_type: 'reply',
        variant: idx === 0 ? 'primary' : 'secondary',
        payload: { reply: opt }
      }))
    },
    layout: { width: 'full', order: 1 }
  });
}

// Action Buttons (toujours present sauf clarification)
if (result.mode !== 'needs_clarification') {
  const actions = result.mode === 'production' ? [
    { id: 'approve', label: 'Approuver', icon: 'check', action_type: 'approve', variant: 'primary', payload: { action: 'approve' } },
    { id: 'regenerate', label: 'Regenerer', icon: 'refresh', action_type: 'navigate', variant: 'secondary', payload: { action: 'regenerate' } },
    { id: 'variants', label: 'Plus de variantes', icon: 'copy', action_type: 'navigate', variant: 'secondary', payload: { action: 'variants' } },
    { id: 'download', label: 'Telecharger', icon: 'download', action_type: 'download', variant: 'ghost', payload: { format: 'zip' } }
  ] : [
    { id: 'develop_1', label: 'Developper Concept 1', icon: 'arrow_right', action_type: 'navigate', variant: 'primary', payload: { concept: 1 } },
    { id: 'develop_2', label: 'Developper Concept 2', icon: 'arrow_right', action_type: 'navigate', variant: 'secondary', payload: { concept: 2 } },
    { id: 'more_ideas', label: 'Plus d\'idees', icon: 'lightbulb', action_type: 'navigate', variant: 'ghost', payload: { action: 'more' } }
  ];

  uiComponents.push({
    type: 'ACTION_BUTTONS',
    data: { layout: 'horizontal', actions: actions },
    layout: { width: 'full', order: 10 }
  });
}

// ─────────────────────────────────────────────────────────────────────────
// FINAL RESPONSE
// ─────────────────────────────────────────────────────────────────────────

const uiResponse = {
  thought_process: {
    step: `Creative ${result.mode === 'production' ? 'Production' : result.mode === 'brainstorming' ? 'Brainstorming' : 'Clarification'} Complete`,
    reasoning: `Mode: ${result.mode}. ${result.mode === 'production' ? 'Pub generee avec angle ' + result.final_ad?.creative_angle : result.mode === 'brainstorming' ? result.recommendations?.length + ' concepts proposes' : 'Clarification requise'}`,
    tools_used: ['creative_brain_ai', 'brand_memory'],
    data_sources: ['Brand Identity', 'Tone of Voice', 'Platform Specs'],
    confidence: result.mode === 'production' ? 0.92 : 0.85,
    persona_context: 'creative_v5'
  },

  chat_message: {
    content: chatMsg.content || 'Creative generee.',
    tone: result.mode === 'production' ? 'positive' : 'neutral',
    follow_up_questions: chatMsg.follow_up_questions || []
  },

  ui_components: uiComponents,

  meta: {
    agent_id: 'creative',
    timestamp: new Date().toISOString(),
    request_id: `req_creative_${Date.now()}`,
    mode: result.mode,
    platform: ctx.platform
  }
};

return [{ json: uiResponse }];
